mapper.select:
SELECT A.TOTAL_REVENUE, A.TOTAL_COUNT, A.CANCEL_COUNT, ROUND((A.TOTAL_STAYS / NULLIF(B.HOTEL_CAPACITY, 0)) * 100, 1) AS OCCUPANCY_RATE FROM ( SELECT NVL(SUM(CASE WHEN r.reservation_status IN ('CONFIRMED', 'CHECKED_IN', 'CHECKED_OUT') THEN p.payment_amount ELSE 0 END), 0) AS TOTAL_REVENUE, COUNT(CASE WHEN r.reservation_status IN ('CONFIRMED', 'CHECKED_IN', 'CHECKED_OUT') THEN 1 END) AS TOTAL_COUNT, COUNT(CASE WHEN r.reservation_status = 'CANCELLED' THEN 1 END) AS CANCEL_COUNT, NVL(SUM(CASE WHEN r.reservation_status IN ('CONFIRMED', 'CHECKED_IN', 'CHECKED_OUT') THEN (r.checkout_date - r.checkin_date) ELSE 0 END), 0) AS TOTAL_STAYS FROM PAYMENT p JOIN RESERVATION r ON p.payment_id = r.payment_id JOIN ROOM_TYPE rt ON r.room_type_id = rt.room_type_id JOIN tbl_hotel h ON rt.fk_hotel_id = h.hotel_id WHERE TO_CHAR(p.paid_at, 'YYYY-MM') = #{month}
AND h.hotel_id = #{hotelId}
AND h.hotel_name = #{hotelName}
) A, ( SELECT NVL(SUM(rt2.total_count), 0) * TO_NUMBER(TO_CHAR(LAST_DAY(TO_DATE(#{month}, 'YYYY-MM')), 'DD')) AS HOTEL_CAPACITY FROM ROOM_TYPE rt2 JOIN tbl_hotel h2 ON rt2.fk_hotel_id = h2.hotel_id
h2.hotel_id = #{hotelId}
AND h2.hotel_name = #{hotelName}
) B

SELECT TO_CHAR(p.paid_at, 'DD') AS PAID_DAY, SUM(p.payment_amount) AS DAILY_REVENUE FROM PAYMENT p JOIN RESERVATION r ON p.payment_id = r.payment_id JOIN ROOM_TYPE rt ON r.room_type_id = rt.room_type_id JOIN tbl_hotel h ON rt.fk_hotel_id = h.hotel_id WHERE TO_CHAR(p.paid_at, 'YYYY-MM') = #{month} AND r.reservation_status IN ('CONFIRMED', 'CHECKED_IN', 'CHECKED_OUT')
AND h.hotel_id = #{hotelId}
AND h.hotel_name = #{hotelName}
GROUP BY TO_CHAR(p.paid_at, 'DD') ORDER BY PAID_DAY

SELECT TO_CHAR(p.paid_at, 'YYYY-MM-DD HH24:MI') AS PAID_AT, p.payment_id AS PAYMENT_ID, m.name AS MEMBER_NAME, p.payment_amount AS PAYMENT_AMOUNT, r.reservation_status AS PAYMENT_STATUS, h.hotel_name AS HOTEL_NAME FROM PAYMENT p JOIN RESERVATION r ON p.payment_id = r.payment_id JOIN tbl_member_security m ON p.member_no = m.member_no JOIN ROOM_TYPE rt ON r.room_type_id = rt.room_type_id JOIN tbl_hotel h ON rt.fk_hotel_id = h.hotel_id WHERE TO_CHAR(p.paid_at, 'YYYY-MM') = #{month}
AND h.hotel_id = #{hotelId}
AND h.hotel_name = #{hotelName}
ORDER BY p.paid_at DESC

SELECT rt.room_name AS ROOM_TYPE, SUM(p.payment_amount) AS TYPE_REVENUE FROM PAYMENT p JOIN RESERVATION r ON p.payment_id = r.payment_id JOIN ROOM_TYPE rt ON r.room_type_id = rt.room_type_id JOIN tbl_hotel h ON rt.fk_hotel_id = h.hotel_id WHERE TO_CHAR(p.paid_at, 'YYYY-MM') = #{month} AND r.reservation_status IN ('CONFIRMED', 'CHECKED_IN', 'CHECKED_OUT')
AND h.hotel_id = #{hotelId}
AND h.hotel_name = #{hotelName}
GROUP BY rt.room_name
